import axios from 'axios';
import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { TrustStars } from './TrustCenter';

const API_URL = process.env.REACT_APP_API_URL || '';

const ACCOUNT_BADGES = {
  team: { label: 'Small Team', icon: '👥', bg: '#eff6ff', color: '#1d4ed8' },
  business: { label: 'Business', icon: '🏢', bg: '#f5f3ff', color: '#6d28d9' },
};

function Profile({ user, setUser }) {
  const [services, setServices] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [mirror, setMirror] = useState(null);
  const [trust, setTrust] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [message, setMessage] = useState('');
  const fileInputRef = useRef(null);
  const token = localStorage.getItem('token');

  useEffect(() => {
    fetchMyServices();
    fetchTransactions();
    fetchMirror();
    fetchTrust();
  }, []);

  const fetchTrust = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/users/me/trust`, {
        headers: { Authorization: 'Bearer ' + token }
      });
      setTrust(res.data);
    } catch { setTrust(null); }
  };

  const showMsg = (msg, t = 3000) => {
    setMessage(msg);
    setTimeout(() => setMessage(''), t);
  };

  const fetchMyServices = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/services/my-services`, {
        headers: { Authorization: 'Bearer ' + token }
      });
      setServices(res.data);
    } catch { setServices([]); }
  };

  const fetchTransactions = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/transactions/my-transactions`, {
        headers: { Authorization: 'Bearer ' + token }
      });
      setTransactions(res.data);
    } catch { setTransactions([]); }
  };

  const fetchMirror = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/reviews/me/mirror`, {
        headers: { Authorization: 'Bearer ' + token }
      });
      setMirror(res.data);
    } catch { setMirror(null); }
  };

  const handleProfileImageUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 5 * 1024 * 1024) { showMsg('Image must be under 5MB'); return; }
    setUploading(true);
    const formData = new FormData();
    formData.append('profileImage', file);
    try {
      const res = await axios.post(`${API_URL}/api/users/profile-image`, formData, {
        headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'multipart/form-data' }
      });
      const updatedUser = { ...user, profileImage: res.data.imageUrl };
      setUser(updatedUser);
      localStorage.setItem('gshop_user', JSON.stringify(updatedUser));
      showMsg('Profile picture updated!');
    } catch (err) {
      showMsg(err.response?.data?.error || 'Upload failed');
    }
    setUploading(false);
  };

  const handleStatusChange = async (isOnline) => {
    try {
      await axios.put(`${API_URL}/api/users/status`, { isOnline }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      const updatedUser = { ...user, isOnline };
      setUser(updatedUser);
      localStorage.setItem('gshop_user', JSON.stringify(updatedUser));
    } catch { showMsg('Status update failed'); }
  };

  const handleToggleMapLock = async (service) => {
    try {
      const nextLock = !service.mapPinLocked;
      const res = await axios.patch(`${API_URL}/api/services/${service._id}/map-lock`, {
        mapPinLocked: nextLock,
        mapVisibility: nextLock ? 'public' : 'hidden'
      }, {
        headers: { Authorization: `Bearer ${token}` }
      });

      setServices(prev => prev.map(s => s._id === service._id ? res.data.service : s));
      showMsg(nextLock ? 'Service locked on map' : 'Service unlocked (now hidden)');
    } catch (err) {
      showMsg(err.response?.data?.error || 'Failed to update map lock');
    }
  };

  const handleDeleteService = async (service) => {
    try {
      await axios.delete(`${API_URL}/api/services/${service._id}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setServices(prev => prev.filter(s => s._id !== service._id));
      showMsg('Service deleted');
    } catch (err) {
      showMsg(err.response?.data?.error || 'Failed to delete service');
    }
  };

  const isOnline = user.isOnline !== false;
  const avatarUrl = user.profileImage ? `${API_URL}${user.profileImage}` : null;
  const myId = String(user.id || user._id || '');

  const sectionCard = {
    background: 'white',
    borderRadius: 20,
    padding: '18px',
    marginBottom: 12,
    boxShadow: '0 1px 4px rgba(0,0,0,0.04)',
    border: '1px solid #f1f5f9',
  };

  const sectionTitle = {
    fontSize: 15,
    fontWeight: 800,
    color: '#1e293b',
    margin: '0 0 14px',
    letterSpacing: '-0.01em',
  };

  return (
    <div style={{ maxWidth: 600, margin: '0 auto', padding: '12px 14px calc(100px + env(safe-area-inset-bottom, 0px))' }}>
      {/* Toast */}
      {message && (
        <div style={{
          position: 'fixed', top: 16, left: '50%', transform: 'translateX(-50%)',
          zIndex: 9999, background: message.includes('failed') || message.includes('error') ? '#ef4444' : '#10b981',
          color: 'white', padding: '12px 20px', borderRadius: 14, fontWeight: 600, fontSize: 13,
          boxShadow: '0 4px 16px rgba(0,0,0,0.15)', whiteSpace: 'nowrap',
        }}>
          {message}
        </div>
      )}

      {/* ── Profile Header ── */}
      <div style={{ ...sectionCard, textAlign: 'center', padding: '24px 18px' }}>
        {/* Avatar */}
        <div style={{ position: 'relative', display: 'inline-block', marginBottom: 14 }}>
          <div
            onClick={() => fileInputRef.current?.click()}
            style={{
              width: 96, height: 96, borderRadius: '50%',
              background: avatarUrl
                ? `url(${avatarUrl}) center/cover`
                : 'linear-gradient(135deg, #6366f1, #4f46e5)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 36, color: 'white', fontWeight: 700,
              cursor: 'pointer', border: '3px solid #e2e8f0',
              margin: '0 auto',
            }}
          >
            {!avatarUrl && user.name?.charAt(0).toUpperCase()}
            {uploading && (
              <div style={{
                position: 'absolute', inset: 0, borderRadius: '50%',
                background: 'rgba(0,0,0,0.5)', display: 'flex',
                alignItems: 'center', justifyContent: 'center', fontSize: 20,
              }}>⏳</div>
            )}
          </div>
          {/* Online dot */}
          <div style={{
            position: 'absolute', bottom: 4, right: 4,
            width: 20, height: 20, borderRadius: '50%',
            background: isOnline ? '#22c55e' : '#9ca3af',
            border: '3px solid white',
          }} />
          <input ref={fileInputRef} type="file" accept="image/*" style={{ display: 'none' }} onChange={handleProfileImageUpload} />
        </div>

        {/* Name */}
        <h2 style={{ margin: '0 0 4px', fontSize: 22, fontWeight: 800, color: '#1e293b' }}>{user.name}</h2>
        {ACCOUNT_BADGES[user.accountType] && (
          <div style={{
            display: 'inline-flex', alignItems: 'center', gap: 6, marginBottom: 6,
            background: ACCOUNT_BADGES[user.accountType].bg, color: ACCOUNT_BADGES[user.accountType].color,
            padding: '4px 12px', borderRadius: 20, fontSize: 12, fontWeight: 700,
          }}>
            <span>{ACCOUNT_BADGES[user.accountType].icon}</span>
            {user.businessName || ACCOUNT_BADGES[user.accountType].label}
            {user.accountType === 'team' && user.teamSize > 1 && <span style={{ opacity: 0.7 }}>· {user.teamSize} people</span>}
          </div>
        )}
        <p style={{ margin: '0 0 14px', color: '#64748b', fontSize: 13 }}>{user.email}</p>

        {/* Balance Pill */}
        <div style={{
          display: 'inline-flex', alignItems: 'center', gap: 10,
          background: 'linear-gradient(135deg, #f0fdf4, #dcfce7)',
          border: '1px solid #bbf7d0', borderRadius: 14,
          padding: '10px 18px', marginBottom: 16,
        }}>
          <span style={{ fontSize: 20 }}>💰</span>
          <div style={{ textAlign: 'left' }}>
            <div style={{ fontSize: 18, fontWeight: 800, color: '#166534' }}>R{user.randBalance ?? 0}</div>
            <div style={{ fontSize: 11, color: '#15803d', fontWeight: 600 }}>Available</div>
          </div>
          {user.escrowRand > 0 && (
            <div style={{ borderLeft: '1px solid #bbf7d0', paddingLeft: 10, textAlign: 'left' }}>
              <div style={{ fontSize: 14, fontWeight: 700, color: '#f59e0b' }}>R{user.escrowRand}</div>
              <div style={{ fontSize: 11, color: '#a16207', fontWeight: 600 }}>Held</div>
            </div>
          )}
        </div>

        {/* Online/Offline Toggle */}
        <div style={{ display: 'flex', gap: 8, justifyContent: 'center' }}>
          <button onClick={() => handleStatusChange(true)} style={{
            flex: 1, maxWidth: 120, padding: '8px 12px', borderRadius: 12,
            border: '2px solid ' + (isOnline ? '#22c55e' : '#e2e8f0'),
            background: isOnline ? '#dcfce7' : 'white',
            color: isOnline ? '#166534' : '#64748b',
            fontSize: 12, fontWeight: 700, cursor: 'pointer',
            display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6,
          }}>
            <span style={{ width: 8, height: 8, borderRadius: '50%', background: '#22c55e' }} />
            Online
          </button>
          <button onClick={() => handleStatusChange(false)} style={{
            flex: 1, maxWidth: 120, padding: '8px 12px', borderRadius: 12,
            border: '2px solid ' + (!isOnline ? '#9ca3af' : '#e2e8f0'),
            background: !isOnline ? '#f1f5f9' : 'white',
            color: !isOnline ? '#374151' : '#94a3b8',
            fontSize: 12, fontWeight: 700, cursor: 'pointer',
            display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6,
          }}>
            <span style={{ width: 8, height: 8, borderRadius: '50%', background: '#9ca3af' }} />
            Offline
          </button>
        </div>
      </div>

      {/* ── Trust Score ── */}
      {trust && (
        <Link to="/verification" style={{ textDecoration: 'none' }}>
          <div style={{
            ...sectionCard,
            display: 'flex', alignItems: 'center', gap: 14, cursor: 'pointer',
            background: 'linear-gradient(135deg, #fffbeb, #fef3c7)',
            border: '1px solid #fde68a',
          }}>
            <div style={{ fontSize: 30, flexShrink: 0 }}>🛡️</div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexWrap: 'wrap' }}>
                <TrustStars stars={trust.stars} size={16} />
                <span style={{ fontSize: 12, fontWeight: 800, color: '#b45309' }}>{trust.level}</span>
              </div>
              <div style={{ height: 6, background: 'rgba(255,255,255,0.7)', borderRadius: 3, overflow: 'hidden', margin: '8px 0 4px' }}>
                <div style={{ width: `${trust.score}%`, height: '100%', background: 'linear-gradient(90deg, #f59e0b, #22c55e)', borderRadius: 3 }} />
              </div>
              <div style={{ fontSize: 11, color: '#92400e', fontWeight: 600 }}>
                {trust.score < 100
                  ? `${trust.score}/100 — add ID, address or qualifications to earn more stars`
                  : 'Fully verified — maximum trust!'}
              </div>
            </div>
            <span style={{ color: '#d97706', fontWeight: 800, fontSize: 18, flexShrink: 0 }}>›</span>
          </div>
        </Link>
      )}

      {/* ── Stats Row ── */}
      {mirror && (
        <div style={{ display: 'flex', gap: 8, overflowX: 'auto', paddingBottom: 4, marginBottom: 12, scrollbarWidth: 'none' }}>
          <div style={{ flexShrink: 0, background: 'white', borderRadius: 16, padding: '14px 18px', border: '1px solid #f1f5f9', textAlign: 'center', minWidth: 100 }}>
            <div style={{ fontSize: 22, fontWeight: 800, color: '#4f46e5' }}>{mirror.stats?.receivedRatingsAvg?.toFixed(1) || '—'}</div>
            <div style={{ fontSize: 11, color: '#64748b', marginTop: 2, fontWeight: 600 }}>⭐ Rating</div>
          </div>
          <div style={{ flexShrink: 0, background: 'white', borderRadius: 16, padding: '14px 18px', border: '1px solid #f1f5f9', textAlign: 'center', minWidth: 100 }}>
            <div style={{ fontSize: 22, fontWeight: 800, color: '#0ea5e9' }}>{mirror.stats?.jobsCompleted || 0}</div>
            <div style={{ fontSize: 11, color: '#64748b', marginTop: 2, fontWeight: 600 }}>Jobs Done</div>
          </div>
          <div style={{ flexShrink: 0, background: 'white', borderRadius: 16, padding: '14px 18px', border: '1px solid #f1f5f9', textAlign: 'center', minWidth: 100 }}>
            <div style={{ fontSize: 22, fontWeight: 800, color: mirror.stats?.reliabilityScore >= 80 ? '#22c55e' : '#f59e0b' }}>
              {mirror.stats?.reliabilityScore ?? 100}%
            </div>
            <div style={{ fontSize: 11, color: '#64748b', marginTop: 2, fontWeight: 600 }}>Reliable</div>
          </div>
          <div style={{ flexShrink: 0, background: 'white', borderRadius: 16, padding: '14px 18px', border: '1px solid #f1f5f9', textAlign: 'center', minWidth: 100 }}>
            <div style={{ fontSize: 22, fontWeight: 800, color: '#8b5cf6' }}>{mirror.stats?.givenRatingsAvg?.toFixed(1) || '—'}</div>
            <div style={{ fontSize: 11, color: '#64748b', marginTop: 2, fontWeight: 600 }}>Given</div>
          </div>
        </div>
      )}

      {/* ── Skills ── */}
      <div style={sectionCard}>
        <div style={sectionTitle}>🛠️ Skills</div>
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
          {user.skills?.length > 0 ? user.skills.map(skill => (
            <span key={skill} style={{
              background: '#f1f5f9', color: '#475569', padding: '6px 14px',
              borderRadius: 20, fontSize: 12, fontWeight: 700,
            }}>{skill}</span>
          )) : (
            <p style={{ color: '#94a3b8', fontSize: 13, margin: 0 }}>No skills added yet.</p>
          )}
        </div>
      </div>

      {/* ── My Services ── */}
      <div style={sectionCard}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}>
          <div style={sectionTitle}>📋 My Services ({services.length})</div>
          <Link to="/create-service" style={{
            padding: '8px 14px', borderRadius: 12, background: '#6366f1', color: 'white',
            fontSize: 12, fontWeight: 700, textDecoration: 'none', flexShrink: 0,
          }}>+ New</Link>
        </div>

        {services.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '20px 0' }}>
            <div style={{ fontSize: 32, marginBottom: 8 }}>📋</div>
            <div style={{ fontSize: 13, color: '#64748b', fontWeight: 600 }}>No services yet</div>
            <div style={{ fontSize: 12, color: '#94a3b8', marginTop: 4 }}>Your first one is FREE</div>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            {services.map(service => (
              <div key={service._id} style={{
                padding: '14px', borderRadius: 14, border: '1px solid #e2e8f0',
                background: '#fafbfc', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start',
              }}>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontWeight: 700, fontSize: 14, color: '#1e293b' }}>{service.title}</div>
                  <div style={{ fontSize: 12, color: '#64748b', marginTop: 2, lineHeight: 1.4 }}>{service.description}</div>
                  <span style={{
                    display: 'inline-block', marginTop: 8, background: '#eef2ff', color: '#4f46e5',
                    padding: '3px 10px', borderRadius: 20, fontSize: 11, fontWeight: 700,
                  }}>{service.category}</span>
                </div>
                <div style={{ textAlign: 'right', flexShrink: 0, marginLeft: 10 }}>
                  <div style={{ fontWeight: 800, color: '#4f46e5', fontSize: 14 }}>
                    {service.pricingType === 'quote' ? '📋 Quote' : `R${service.randAmount || 0}`}
                  </div>
                  <div style={{ marginTop: 8, display: 'flex', flexDirection: 'column', gap: 6 }}>
                    <span style={{
                      display: 'inline-block',
                      padding: '3px 8px',
                      borderRadius: 10,
                      fontSize: 10,
                      fontWeight: 700,
                      background: service.mapPinLocked ? '#dcfce7' : '#fef3c7',
                      color: service.mapPinLocked ? '#166534' : '#92400e'
                    }}>
                      {service.mapPinLocked ? '📍 Locked on Map' : `🙈 ${service.mapVisibility === 'hidden' ? 'Hidden from Map' : 'Visible on Map'}`}
                    </span>
                    <button
                      onClick={() => handleToggleMapLock(service)}
                      style={{
                        border: 'none',
                        borderRadius: 10,
                        padding: '6px 10px',
                        fontSize: 11,
                        fontWeight: 700,
                        cursor: 'pointer',
                        background: service.mapPinLocked ? '#fef3c7' : '#dcfce7',
                        color: service.mapPinLocked ? '#92400e' : '#166534'
                      }}
                    >
                      {service.mapPinLocked ? 'Unlock Map Pin' : 'Lock on Map'}
                    </button>
                    <button
                      onClick={() => handleDeleteService(service)}
                      style={{
                        border: 'none',
                        borderRadius: 10,
                        padding: '6px 10px',
                        fontSize: 11,
                        fontWeight: 700,
                        cursor: service.mapPinLocked ? 'not-allowed' : 'pointer',
                        background: service.mapPinLocked ? '#fee2e2' : '#ef4444',
                        color: service.mapPinLocked ? '#b91c1c' : 'white',
                        opacity: service.mapPinLocked ? 0.7 : 1
                      }}
                      disabled={service.mapPinLocked}
                      title={service.mapPinLocked ? 'Unlock map pin first' : 'Delete service'}
                    >
                      Delete
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* ── Transaction History ── */}
      <div style={sectionCard}>
        <div style={sectionTitle}>📊 Recent Transactions</div>
        {transactions.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '20px 0' }}>
            <div style={{ fontSize: 32, marginBottom: 8 }}>📊</div>
            <div style={{ fontSize: 13, color: '#64748b', fontWeight: 600 }}>No transactions yet</div>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
            {transactions.slice(0, 8).map(t => (
              <div key={t._id} style={{
                padding: '12px 14px', borderRadius: 14, border: '1px solid #e2e8f0',
                background: '#fafbfc', display: 'flex', justifyContent: 'space-between', alignItems: 'center',
              }}>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontWeight: 700, fontSize: 13, color: '#1e293b' }}>{t.serviceTitle || 'Service'}</div>
                  <div style={{ fontSize: 11, color: '#94a3b8', marginTop: 2 }}>
                    {String(t.requesterId?._id || t.requesterId) === myId ? 'You paid' : 'You received'} • {t.paymentMethod === 'cash' ? 'Cash' : 'Escrow'}
                  </div>
                </div>
                <div style={{ textAlign: 'right', flexShrink: 0, marginLeft: 10 }}>
                  <div style={{
                    fontWeight: 800, fontSize: 14,
                    color: String(t.requesterId?._id || t.requesterId) === myId ? '#ef4444' : '#22c55e',
                  }}>
                    {String(t.requesterId?._id || t.requesterId) === myId ? '-' : '+'}{t.negotiatedAmount || t.randAmount || t.credits || 0}
                  </div>
                  <span style={{
                    display: 'inline-block', marginTop: 2, padding: '2px 8px', borderRadius: 10,
                    fontSize: 10, fontWeight: 700,
                    background: t.status === 'completed' ? '#dcfce7' : t.status === 'cancelled' ? '#fee2e2' : '#fef3c7',
                    color: t.status === 'completed' ? '#166534' : t.status === 'cancelled' ? '#991b1b' : '#92400e',
                  }}>{t.status}</span>
                </div>
              </div>
            ))}
            {transactions.length > 8 && (
              <div style={{ textAlign: 'center', fontSize: 12, color: '#94a3b8', padding: '8px 0' }}>
                +{transactions.length - 8} more transactions
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

export default Profile;
